102	function reimbursementFor(damage: Damage, policyItems: Item[]): number {
103	  if (damage.amount < 0) {
104	    throw new Error(`Negative damage amount: ${damage.amount}`);
105	  }
106	  const insuredItem = policyItems.find((item) => item.type === damage.itemType);
107	  if (insuredItem === undefined) {
108	    throw new Error(`Claim references item type not in policy: ${damage.itemType}`);
109	  }
110	  const adjustedAmount = adjustForEnchantment(damage.amount, insuredItem);
111	  return Math.max(0, adjustedAmount - DEDUCTIBLE_PER_DAMAGE);
112	}
